    fun testNanoDelay() = runTest {
        val deferred = async {
            expect(2)
            delay(1.nanoseconds)
            expect(4)
        }

        expect(1)
        yield()
        expect(3)
        deferred.await()
        finish(5)
    }

    @Test
    fun testToDelayMillisRoundsUp() {
        // Sub-millisecond durations should be rounded up to 1ms
        assertEquals(1L, 1.nanoseconds.toDelayMillis())
        assertEquals(1L, 999999.nanoseconds.toDelayMillis())
        assertEquals(1L, 1.microseconds.toDelayMillis())
        assertEquals(1L, 999.microseconds.toDelayMillis())

        // Exact millisecond durations should not change
        assertEquals(1L, 1.milliseconds.toDelayMillis())
        assertEquals(10L, 10.milliseconds.toDelayMillis())
        assertEquals(1000L, 1.seconds.toDelayMillis())

        // Durations with sub-millisecond components should be rounded up
        assertEquals(2L, (1.milliseconds + 1.nanoseconds).toDelayMillis())
        assertEquals(2L, (1.milliseconds + 500.microseconds).toDelayMillis())
        assertEquals(999L, (998.milliseconds + 902752.nanoseconds).toDelayMillis())

        // Zero and negative durations should return 0
        assertEquals(0L, Duration.ZERO.toDelayMillis())
        assertEquals(0L, (-1).milliseconds.toDelayMillis())
        assertEquals(0L, (-1).nanoseconds.toDelayMillis())

        // Infinite duration should return Long.MAX_VALUE
        assertEquals(Long.MAX_VALUE, Duration.INFINITE.toDelayMillis())
    }

    private suspend fun runAndCancel(time: Duration) = coroutineScope {"}

