import kotlinx.coroutines.testing.*
import org.junit.Test
import java.lang.ref.*
import kotlin.coroutines.*
import kotlin.test.*

/**
 * Tests that verify UndispatchedCoroutine does not leak CoroutineContext via thread locals
 * when using custom ContinuationInterceptors that are not CoroutineDispatchers.
 * 
 * See https://github.com/Kotlin/kotlinx.coroutines/issues/4295
 */
class CustomContinuationInterceptorTest : TestBase() {

    @Test
    fun testCoroutineDispatcherNotSuspendingDoesNotLeakCoroutineContext() =
        ensureCoroutineContextGCed(Dispatchers.Default, suspend = false)

    @Test
    fun testCoroutineDispatcherSuspendingDoesNotLeakCoroutineContext() =
        ensureCoroutineContextGCed(Dispatchers.Default, suspend = true)

    @Test
    fun testCustomContinuationInterceptorSuspendingDoesNotLeakCoroutineContext() =
        ensureCoroutineContextGCed(
            CustomContinuationInterceptor(Dispatchers.Default),
            suspend = true
        )

    /**
     * This is the main test case that was failing before the fix.
     * When using a custom ContinuationInterceptor (not a CoroutineDispatcher) and the
     * coroutine completes without suspending, the UndispatchedCoroutine.init block
     * would save thread context but afterResume() would never be called to clean it up.
     */
    @Test
    fun testCustomContinuationInterceptorNotSuspendingDoesNotLeakCoroutineContext() =
        ensureCoroutineContextGCed(
            CustomContinuationInterceptor(Dispatchers.Default),
            suspend = false
        )

    @Test
    fun testCustomNeverEqualContinuationInterceptorSuspendingDoesNotLeakCoroutineContext() =
        ensureCoroutineContextGCed(
            CustomNeverEqualContinuationInterceptor(Dispatchers.Default),
            suspend = true
        )

    @Test
    fun testCustomNeverEqualContinuationInterceptorNotSuspendingDoesNotLeakCoroutineContext() =
        ensureCoroutineContextGCed(
            CustomNeverEqualContinuationInterceptor(Dispatchers.Default),
            suspend = false
        )

    private fun ensureCoroutineContextGCed(coroutineContext: CoroutineContext, suspend: Boolean) {
        runTest {
            lateinit var ref: WeakReference<CoroutineName>
            val job = GlobalScope.launch(coroutineContext) {
                val coroutineName = CoroutineName("Yo")
                ref = WeakReference(coroutineName)
                withContext(coroutineName) {
                    if (suspend) {
                        delay(1)
                    }
                }
            }
            job.join()

            System.gc()
            assertNull(ref.get())
        }
    }
}

/**
 * A custom ContinuationInterceptor that delegates to another interceptor.
 * This is NOT a CoroutineDispatcher, which triggers the special path in UndispatchedCoroutine.init.
 */
class CustomContinuationInterceptor(private val delegate: ContinuationInterceptor) :
    AbstractCoroutineContextElement(ContinuationInterceptor), ContinuationInterceptor {

    override fun <T> interceptContinuation(continuation: Continuation<T>): Continuation<T> {
        return delegate.interceptContinuation(continuation)
    }
}

/**
 * A custom ContinuationInterceptor that always returns false for equals().
 * This forces withContext to take a different path (not the UndispatchedCoroutine fast path).
 */
class CustomNeverEqualContinuationInterceptor(private val delegate: ContinuationInterceptor) :
    AbstractCoroutineContextElement(ContinuationInterceptor), ContinuationInterceptor {

    override fun <T> interceptContinuation(continuation: Continuation<T>): Continuation<T> {
        return delegate.interceptContinuation(continuation)
    }

    override fun equals(other: Any?) = false
}
"}

