 24→@Suppress("UNCHECKED_CAST")
 25→internal fun <E : Throwable> tryCopyException(exception: E): E? {
 26→    // Fast path for CopyableThrowable
 27→    if (exception is CopyableThrowable<*>) {
 28→        return runCatching { exception.createCopy() as E? }.getOrNull()
 29→    }
 30→    return ctorCache.get(exception.javaClass).invoke(exception) as E?
 31→}
 32→
 33→private fun <E : Throwable> createConstructor(clz: Class<E>): Ctor {
 34→    val nullResult: Ctor = { null } // Pre-cache class
 35→    // Skip reflective copy if an exception has additional fields (that are usually populated in user-defined constructors)
 36→    if (throwableFields != clz.fieldsCountOrDefault(0)) return nullResult
 37→    /*
 38→    * Try to reflectively find constructor(), constructor(message, cause), constructor(cause) or constructor(message).
 39→    * Exceptions are shared among coroutines, so we should copy exception before recovering current stacktrace.
 40→    *
 41→    * Constructors are prioritized in the following order (best to worst):
 42→    * 1. (String, Throwable) - preserves both message and cause
 43→    * 2. (Throwable) - preserves the cause chain directly
 44→    * 3. (String) - preserves message, sets cause via initCause
 45→    * 4. () - requires initCause to set the cause
 46→    */
 47→    var bestCtor: Ctor? = null
 48→    var bestCtorPriority = -1
 49→    for (constructor in clz.constructors) {
 50→        val (priority, ctor) = createSafeConstructorWithPriority(constructor)
 51→        if (priority > bestCtorPriority) {
 52→            bestCtorPriority = priority
 53→            bestCtor = ctor
 54→        }
 55→    }
 56→    return bestCtor ?: nullResult
 57→}
 58→
 59→/**
 60→ * Creates a safe constructor wrapper with an associated priority.
 61→ * Higher priority values indicate better constructors for exception copying.
 62→ *
 63→ * Priority values:
 64→ * - 4: (String, Throwable) - best, preserves both message and cause
 65→ * - 3: (Throwable) - preserves the cause chain directly
 66→ * - 2: (String) - preserves message, sets cause via initCause
 67→ * - 1: () - requires initCause to set the cause
 68→ * - -1: not a viable constructor
 69→ */
 70→private fun createSafeConstructorWithPriority(constructor: Constructor<*>): Pair<Int, Ctor?> {
 71→    val p = constructor.parameterTypes
 72→    return when (p.size) {
 73→        2 -> when {
 74→            p[0] == String::class.java && p[1] == Throwable::class.java ->
 75→                4 to safeCtor { e -> constructor.newInstance(e.message, e) as Throwable }
 76→            else -> -1 to null
 77→        }
 78→        1 -> when (p[0]) {
 79→            Throwable::class.java ->
 80→                3 to safeCtor { e -> constructor.newInstance(e) as Throwable }
 81→            String::class.java ->
 82→                2 to safeCtor { e -> (constructor.newInstance(e.message) as Throwable).also { it.initCause(e) } }
 83→            else -> -1 to null
 84→        }
 85→        0 -> 1 to safeCtor { e -> (constructor.newInstance() as Throwable).also { it.initCause(e) } }
 86→        else -> -1 to null
 87→    }
 88→}
 89→
 90→private inline fun safeCtor(crossinline block: (Throwable) -> Throwable): Ctor =
 91→    { e -> runCatching { block(e) }.getOrNull() }
 92→
 93→private fun Class<*>.fieldsCountOrDefault(defaultValue: Int) =
 94→    kotlin.runCatching { fieldsCount() }.getOrDefault(defaultValue)
 95→
 96→private tailrec fun Class<*>.fieldsCount(accumulator: Int = 0): Int {
 97→    val fieldsCount = declaredFields.count { !Modifier.isStatic(it.modifiers) }
 98→    val totalFields = accumulator + fieldsCount
 99→    val superClass = superclass ?: return totalFields
100→    return superClass.fieldsCount(totalFields)
101→}
102→
103→internal abstract class CtorCache {
104→    abstract fun get(key: Class<out Throwable>): Ctor
105→}
106→
107→private object WeakMapCtorCache : CtorCache() {
108→    private val cacheLock = ReentrantReadWriteLock()
109→    private val exceptionCtors: WeakHashMap<Class<out Throwable>, Ctor> = WeakHashMap()
110→
111→    override fun get(key: Class<out Throwable>): Ctor {
112→        cacheLock.read { exceptionCtors[key]?.let { return it } }
113→        cacheLock.write {
114→            exceptionCtors[key]?.let { return it }
115→            return createConstructor(key).also { exceptionCtors[key] = it }
116→        }
117→    }
118→}
119→
120→@IgnoreJreRequirement
121→private object ClassValueCtorCache : CtorCache() {
122→    private val cache = object : ClassValue<Ctor>() {
123→        override fun computeValue(type: Class<*>?): Ctor {
124→            @Suppress("UNCHECKED_CAST")
125→            return createConstructor(type as Class<out Throwable>)
126→        }
127→    }
128→
129→    override fun get(key: Class<out Throwable>): Ctor = cache.get(key)
130→}
