 90→    val future = CompletableFuture<Unit>()
 91→    setupCancellation(future)
 92→    invokeOnCompletion { cause ->
 93→        if (cause === null) future.complete(Unit)
 94→        else future.completeExceptionally(cause)
 95→    }
